#include <stdio.h>
#include <limits.h>
#define INF INT_MAX
int main() {
    int N;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        int K;
        scanf("%d", &K);
        int **graph = (int **)malloc(K * sizeof(int *));
        for (int j = 0; j < K; j++) {
            graph[j] = (int *)malloc(K * sizeof(int));
            for (int k = 0; k < K; k++) {
                graph[j][k] = INF;
            }
        }
        for (int j = 0; j < K; j++) {
            int F, D;
            scanf("%d %d", &F, &D);
            for (int k = 0; k < D; k++) {
                int village, distance;
                scanf("%d %d", &village, &distance);
                graph[j][village - 1] = distance;
                graph[village - 1][j] = distance;
            }
        }
        int **dist = (int **)malloc(K * sizeof(int *));
        for (int j = 0; j < K; j++) {
            dist[j] = (int *)malloc(K * sizeof(int));
            for (int k = 0; k < K; k++) {
                dist[j][k] = INF;
            }
        }
        for (int j = 0; j < K; j++) {
            dist[j][j] = 0;
        }
        for (int j = 0; j < K; j++) {
            for (int k = 0; k < K; k++) {
                for (int l = 0; l < K; l++) {
                    dist[j][k] = (dist[j][k] < dist[j][l] + graph[l][k]) ? dist[j][k] : dist[j][l] + graph[l][k];
                }
            }
        }
        int minTotalDistance = INF;
        for (int j = 0; j < K; j++) {
            if (graph[0][j] != INF) {
                int totalDistance = 0;
                for (int k = 0; k < K; k++) {
                    totalDistance += dist[k][j];
                }
                minTotalDistance = (minTotalDistance < totalDistance) ? minTotalDistance : totalDistance;
            }
        }
        printf("Case %d: %d\n", i + 1, minTotalDistance);
        for (int j = 0; j < K; j++) {
            free(graph[j]);
            free(dist[j]);
        }
        free(graph);
        free(dist);
    }
    return 0;
}

