                cin >> village >> distance;
                graph[j][village - 1] = distance;
                graph[village - 1][j] = distance;
            }
        }
        vector<vector<int>> dist(K, vector<int>(K, INF));
        for (int j = 0; j < K; j++) {
            dist[j][j] = 0;
        }
        for (int j = 0; j < K; j++) {
            for (int k = 0; k < K; k++) {
                for (int l = 0; l < K; l++) {
                    dist[j][k] = min(dist[j][k], dist[j][l] + graph[l][k]);
                }
            }
        }
        int minTotalDistance = INF;
        for (int j = 0; j < K; j++) {
            if (graph[0][j] != INF) {
                int totalDistance = 0;
                for (int k = 0; k < K; k++) {
                    totalDistance += dist[k][j];
                }
                minTotalDistance = min(minTotalDistance, totalDistance);
            }
        }
        cout << "Case " << i + 1 << ": " << minTotalDistance << endl;
    }
    return 0;
}

