            int K = scanner.nextInt();
            int[][] graph = new int[K][K];
            for (int j = 0; j < K; j++) {
                for (int k = 0; k < K; k++) {
                    graph[j][k] = Integer.MAX_VALUE;
                }
            }
            for (int j = 0; j < K; j++) {
                int F = scanner.nextInt();
                int D = scanner.nextInt();
                for (int k = 0; k < D; k++) {
                    int village = scanner.nextInt();
                    int distance = scanner.nextInt();
                    graph[j][village - 1] = distance;
                    graph[village - 1][j] = distance;
                }
            }
            int[][] dist = new int[K][K];
            for (int j = 0; j < K; j++) {
                for (int k = 0; k < K; k++) {
                    dist[j][k] = Integer.MAX_VALUE;
                }
            }
            for (int j = 0; j < K; j++) {
                dist[j][j] = 0;
            }
            for (int j = 0; j < K; j++) {
                for (int k = 0; k < K; k++) {
                    for (int l = 0; l < K; l++) {
                        dist[j][k] = Math.min(dist[j][k], dist[j][l] + graph[l][k]);
                    }
                }
            }
            int minTotalDistance = Integer.MAX_VALUE;
            for (int j = 0; j < K; j++) {
                if (graph[0][j] != Integer.MAX_VALUE) {
                    int totalDistance = 0;
                    for (int k = 0; k < K; k++) {
                        totalDistance += dist[k][j];
                    }
                    minTotalDistance = Math.min(minTotalDistance, totalDistance);
